/**
 * Name: Memory History
 * Description: Keeps the history messages in memory (this is intended for dev purposes only)
 */

const sessions = {};

const getWidgetInputs = () => [
  { name: 'read', type: DataType.JsonObj },
  { name: 'update', type: [DataType.JsonObj, DataType.Array] }
];

const getWidgetOutputs = () => [
  { name: 'sessionHistoryOutput', type: DataType.JsonObj }
];

const onParentEvent = async ({ targetPort, event }) => {
  const inputData = event.data.value;

  if (targetPort.name === 'read') {
    const sessionId = inputData.sessionId;

    if (sessionId === undefined || sessionId === null) {
      console.error("Error: 'read' event missing 'sessionId' property.");
      return;
    }

    if (!sessions[sessionId]) {
      sessions[sessionId] = { messages: [] };
    }

    await setOutput({ port: 'sessionHistoryOutput', data: { type: DataType.JsonObj, value: sessions[sessionId] } });

  } else if (targetPort.name === 'update') {
    const sessionId = inputData.sessionId;
    const messagesToProcess = inputData.messages;

    if (sessionId === undefined || sessionId === null) {
      console.error("Error: 'update' event missing 'sessionId' property.");
      return;
    }
    if (messagesToProcess === undefined || messagesToProcess === null) {
      console.error("Error: 'update' event missing 'messagesToAdd' property. No messages to add.");
      return;
    }

    if (!sessions[sessionId]) {
      sessions[sessionId] = { messages: [] };
    }

    if (Array.isArray(messagesToProcess)) {
      sessions[sessionId].messages.push(...messagesToProcess);
    } else {
      sessions[sessionId].messages.push(messagesToProcess);
    }
  }
};
